package com.project.utils.zip;

import com.fasterxml.jackson.core.JsonProcessingException;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.fasterxml.jackson.databind.node.ObjectNode;
import com.project.utils.zip.util.GzipUtil;
import com.project.utils.zip.util.PaymentIntentUtil;
import com.project.utils.zip.vo.PaymentIntent;

public class UnzipJsonMain {

    private static final ObjectMapper mapper = new ObjectMapper();

    private static String checkoutToken = "";

    public static void main(String[] args) throws JsonProcessingException {

        if (GzipUtil.isZipped(checkoutToken))
            System.out.println("isZipped: true");

        String unzipped = GzipUtil.unzip(checkoutToken);

        ObjectNode root = (ObjectNode) mapper.readTree(unzipped);

        String valueAsString = root.get("value").asText();
        ObjectNode valueJson = (ObjectNode) mapper.readTree(valueAsString);

        PaymentIntent paymentIntent = PaymentIntentUtil.buildFlexPayPaymentIntent();

        ObjectNode paymentIntentNode = mapper.valueToTree(paymentIntent);

        valueJson.set("paymentIntentRequest", paymentIntentNode);
        root.put("value", mapper.writeValueAsString(valueJson));

        String zipped = GzipUtil.zip(root.toString());
        String unzippedFinal = GzipUtil.unzip(zipped);

        System.out.println(zipped);
        System.out.println(unzippedFinal);
    }
}
